#!/usr/bin/env node
/**
 * Скрипт миграции на @beeline/design-system-react v2.0.0

 */

const fs = require('fs');
const path = require('path');

const PACKAGE_NAME = '@beeline/design-system-react';
const PACKAGE_NAME_ESCAPED = escapeRegExp(PACKAGE_NAME);

const EXTENSIONS = ['.js', '.jsx', '.ts', '.tsx'];
const DEFAULT_IGNORE_DIRS = ['node_modules', 'build', 'dist', '.git', 'coverage', '.next', 'out', '.cache'];

function escapeRegExp(str) {
	return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// -----------------------------------------------------------------------------
// Версия и предупреждение
// -----------------------------------------------------------------------------
function getProjectPackageJson(cwd) {
	const pkgPath = path.join(cwd, 'package.json');
	try {
		return JSON.parse(fs.readFileSync(pkgPath, 'utf8'));
	} catch {
		return null;
	}
}

function getDesignSystemVersion(cwd) {
	const pkg = getProjectPackageJson(cwd);
	const deps = { ...(pkg?.dependencies || {}), ...(pkg?.devDependencies || {}) };
	const ver = deps[PACKAGE_NAME];
	if (!ver) return null;
	// Убираем ^ и ~
	const match = ver.replace(/^[\^~]/, '').match(/^(\d+)\.(\d+)\.(\d+)/);
	return match ? { major: +match[1], minor: +match[2], patch: +match[3], raw: ver } : null;
}

function printVersionWarning(cwd) {
	const v = getDesignSystemVersion(cwd);
	if (!v) {
		console.log('⚠️  В проекте не найдена зависимость @beeline/design-system-react. Скрипт можно запускать для проверки импортов.\n');
		return;
	}
	if (v.major >= 2) {
		console.log(`✅ Обнаружена @beeline/design-system-react v${v.major}.${v.minor}.${v.patch}. CJS и deprecated сборки в v2 больше не поставляются.\n`);
		return;
	}
	console.log(`⚠️  Текущая версия: @beeline/design-system-react ${v.raw}`);
	console.log('   После обновления до 2.0.0 будут удалены: CJS-сборка и сборка /deprecated.');
	console.log('   Запустите этот скрипт с --fix после обновления для автоматической миграции.\n');
}

// -----------------------------------------------------------------------------
// Сканирование файлов
// -----------------------------------------------------------------------------
function* walkFiles(rootDir, ignoreDirs) {
	const stack = [rootDir];
	while (stack.length) {
		const dir = stack.pop();
		let entries;
		try {
			entries = fs.readdirSync(dir, { withFileTypes: true });
		} catch {
			continue;
		}
		for (const e of entries) {
			const full = path.join(dir, e.name);
			const rel = path.relative(rootDir, full);
			if (e.isDirectory()) {
				if (!ignoreDirs.some(ign => rel.startsWith(ign) || e.name === ign)) stack.push(full);
			} else if (e.isFile() && EXTENSIONS.includes(path.extname(e.name))) {
				yield full;
			}
		}
	}
}

// -----------------------------------------------------------------------------
// Поиск паттернов 
// -----------------------------------------------------------------------------

const RE_IMPORT_DEPRECATED = new RegExp(
	`(import\\s+[\\s\\S]*?\\s+from\\s*[\'"])(${PACKAGE_NAME_ESCAPED})/deprecated([\'"])`,
	'g'
);

function findRequireStatements(content) {
	const results = [];
	// const { ... } = require('@beeline/...') — многострочная деструктуризация
	const reDestructure = new RegExp(
		`(const|let|var)\\s*\\{([\\s\\S]*?)\\}\\s*=\\s*require\\s*\\(\\s*[\'"](${PACKAGE_NAME_ESCAPED})(/deprecated)?[\'"]\\s*\\)\\s*;?`,
		'g'
	);
	let m;
	while ((m = reDestructure.exec(content)) !== null) {
		const bindings = m[2]
			.split(',')
			.map(s => s.replace(/\s+/g, ' ').trim())
			.filter(Boolean);
		results.push({
			type: 'destructure',
			full: m[0],
			start: m.index,
			end: m.index + m[0].length,
			binding: bindings,
			deprecated: Boolean(m[4]),
		});
	}
	// const x = require('@beeline/...') — простой namespace-импорт
	const reSimple = new RegExp(
		`(const|let|var)\\s+(\\w+)\\s*=\\s*require\\s*\\(\\s*[\'"](${PACKAGE_NAME_ESCAPED})(/deprecated)?[\'"]\\s*\\)\\s*;?`,
		'g'
	);
	while ((m = reSimple.exec(content)) !== null) {
		// Исключаем совпадения, уже найденные как деструктуризация
		const alreadyFound = results.some(r => r.start === m.index);
		if (!alreadyFound) {
			results.push({
				type: 'namespace',
				full: m[0],
				start: m.index,
				end: m.index + m[0].length,
				binding: m[2],
				deprecated: Boolean(m[4]),
			});
		}
	}
	return results;
}

// Поиск import из /deprecated — поддержка многострочных импортов
function findImportFromDeprecated(content) {
	const results = [];
	// Матчит: import { A,\n  B } from '..../deprecated', import X from '..../deprecated', import * as X from '...'
	const re = new RegExp(
		`import\\s+([\\s\\S]*?)\\s+from\\s*[\'"]${PACKAGE_NAME_ESCAPED}/deprecated[\'"]`,
		'g'
	);
	let m;
	while ((m = re.exec(content)) !== null) {
		results.push({ start: m.index, end: m.index + m[0].length, full: m[0] });
	}
	return results;
}

// Поиск динамических import() из /deprecated
function findDynamicImportDeprecated(content) {
	const results = [];
	const re = new RegExp(
		`import\\s*\\(\\s*[\'"]${PACKAGE_NAME_ESCAPED}/deprecated[\'"]\\s*\\)`,
		'g'
	);
	let m;
	while ((m = re.exec(content)) !== null) {
		results.push({ start: m.index, end: m.index + m[0].length, full: m[0] });
	}
	return results;
}

// -----------------------------------------------------------------------------
// Применение правок
// -----------------------------------------------------------------------------

function fixImportDeprecated(content) {
	return content.replace(RE_IMPORT_DEPRECATED, `$1${PACKAGE_NAME}$3`);
}

function fixDynamicImportDeprecated(content) {
	const re = new RegExp(
		`(import\\s*\\(\\s*[\'"])${PACKAGE_NAME_ESCAPED}/deprecated([\'"]\\s*\\))`,
		'g'
	);
	return content.replace(re, `$1${PACKAGE_NAME}$2`);
}

function fixRequireToImport(content, requireStatements) {
	// Сортируем с конца файла, чтобы индексы не сбивались
	const sorted = [...requireStatements].sort((a, b) => b.start - a.start);

	let result = content;
	const importsToAdd = [];

	for (const st of sorted) {
		const from = `'${PACKAGE_NAME}'`;
		let importLine;
		if (st.type === 'destructure') {
			importLine = `import { ${st.binding.join(', ')} } from ${from};`;
		} else {
			importLine = `import * as ${st.binding} from ${from};`;
		}
		importsToAdd.push(importLine);
		result = result.slice(0, st.start) + result.slice(st.end);
	}

	if (importsToAdd.length === 0) return result;

	const newImportsBlock = importsToAdd.join('\n') + '\n';

	// Вставить импорты в начало: после "use strict", комментариев и пустых строк, перед первым import/export
	const importExportStart = result.search(/\b(?:import|export)\s+/m);
	let insertIndex;
	if (importExportStart !== -1) {
		insertIndex = importExportStart;
	} else {
		// Нет импортов — вставляем после начальных комментариев и 'use strict'
		const top = result.match(/^(\s*(?:['"]use strict['"];?\s*)?(?:\/\*[\s\S]*?\*\/\s*)*(?:\/\/[^\n]*\n\s*)*)/);
		insertIndex = top ? top[0].length : 0;
	}

	result = result.slice(0, insertIndex) + newImportsBlock + result.slice(insertIndex);
	return result;
}

// -----------------------------------------------------------------------------
// Главная логика (один проход: сканирование + кэширование + применение правок)
// -----------------------------------------------------------------------------
function run(cwd, options = {}) {
	const fix = options.fix === true;
	const customIgnore = options.ignore || [];
	const ignoreDirs = [...DEFAULT_IGNORE_DIRS, ...customIgnore];

	printVersionWarning(cwd);

	const issues = [];
	// Кэш: filePath → { content, deprecatedImports, dynamicImports, requireStatements }
	const fileCache = new Map();

	for (const filePath of walkFiles(cwd, ignoreDirs)) {
		const relPath = path.relative(cwd, filePath);
		let content;
		try {
			content = fs.readFileSync(filePath, 'utf8');
		} catch {
			continue;
		}

		const entry = { content, deprecatedImports: [], dynamicImports: [], requireStatements: [] };

		// 1) Статические импорты из /deprecated
		const deprecatedImports = findImportFromDeprecated(content);
		if (deprecatedImports.length > 0) {
			entry.deprecatedImports = deprecatedImports;
			issues.push({
				file: relPath,
				type: 'import-deprecated',
				message: `Импорт из "${PACKAGE_NAME}/deprecated" (${deprecatedImports.length} вхожд.) — заменить на основной пакет`,
				count: deprecatedImports.length,
			});
		}

		// 2) Динамические import() из /deprecated
		const dynamicImports = findDynamicImportDeprecated(content);
		if (dynamicImports.length > 0) {
			entry.dynamicImports = dynamicImports;
			issues.push({
				file: relPath,
				type: 'dynamic-import-deprecated',
				message: `Динамический import("${PACKAGE_NAME}/deprecated") (${dynamicImports.length} вхожд.) — заменить путь`,
				count: dynamicImports.length,
			});
		}

		// 3) require (CJS)
		const requireStatements = findRequireStatements(content);
		if (requireStatements.length > 0) {
			entry.requireStatements = requireStatements;
			const fromDeprecated = requireStatements.filter(s => s.deprecated).length;
			const fromMain = requireStatements.length - fromDeprecated;
			const parts = [];
			if (fromMain > 0) parts.push(`require основного пакета (CJS): ${fromMain}`);
			if (fromDeprecated > 0) parts.push(`require /deprecated: ${fromDeprecated}`);
			issues.push({
				file: relPath,
				type: 'cjs-require',
				message: parts.join('; ') + ' — переписать на ESM import',
				count: requireStatements.length,
			});
		}

		// Сохраняем в кэш только если есть что фиксить
		if (entry.deprecatedImports.length || entry.dynamicImports.length || entry.requireStatements.length) {
			fileCache.set(filePath, entry);
		}
	}

	// Вывод отчёта
	if (issues.length === 0) {
		console.log('✅ Проблем не найдено: CJS и импорты из /deprecated не обнаружены.\n');
		return { ok: true, fixed: 0 };
	}

	console.log('Обнаружено проблем:\n');
	const byFile = new Map();
	for (const i of issues) {
		if (!byFile.has(i.file)) byFile.set(i.file, []);
		byFile.get(i.file).push(i);
	}
	for (const [file, items] of byFile) {
		console.log(`  ${file}`);
		for (const item of items) {
			console.log(`    - ${item.message}`);
		}
		console.log('');
	}

	if (!fix) {
		console.log('Запустите скрипт с флагом --fix, чтобы автоматически заменить импорты и переписать require на ESM.\n');
		return { ok: false, fixed: 0 };
	}

	// Применение правок (один проход по кэшу)
	let fixedCount = 0;

	for (const [filePath, entry] of fileCache) {
		let newContent = entry.content;
		let changed = false;

		// 1) Замена require → import (сначала, т.к. использует индексы из оригинального content)
		if (entry.requireStatements.length > 0) {
			newContent = fixRequireToImport(newContent, entry.requireStatements);
			changed = true;
		}

		// 2) Замена статических import из /deprecated
		const afterStaticFix = fixImportDeprecated(newContent);
		if (afterStaticFix !== newContent) {
			newContent = afterStaticFix;
			changed = true;
		}

		// 3) Замена динамических import() из /deprecated
		const afterDynamicFix = fixDynamicImportDeprecated(newContent);
		if (afterDynamicFix !== newContent) {
			newContent = afterDynamicFix;
			changed = true;
		}

		if (changed) {
			fs.writeFileSync(filePath, newContent, 'utf8');
			fixedCount++;
			console.log(`  [fix] ${path.relative(cwd, filePath)}`);
		}
	}

	console.log(`\n✅ Применено правок в файлах: ${fixedCount}\n`);
	return { ok: true, fixed: fixedCount };
}

// CLI
const cwd = process.cwd();
const args = process.argv.slice(2);
const fix = args.includes('--fix');
const ignoreIndex = args.indexOf('--ignore');
let ignore = [];
if (ignoreIndex !== -1 && args[ignoreIndex + 1]) {
	ignore = args[ignoreIndex + 1].split(',').map(s => s.trim());
}

run(cwd, { fix, ignore });
